/* ─── DISSOLVE ANIM ──────────────────────────────────────── */
function DissolveAnim({ accent }) {
  const [op, setOp] = useState(1);
  useEffect(() => {
    let t = 0;
    const iv = setInterval(() => {
      t += 0.025;
      const c = t % 1;
      setOp(c < 0.25 ? 1 : Math.max(0.05, 1 - (c - 0.25) * 3.5));
    }, 50);
    return () => clearInterval(iv);
  }, []);
  return (
    <div style={{ textAlign: "center", padding: "1.8rem" }}>
      <p
        style={{
          fontFamily: "'Cormorant Garamond',serif",
          fontSize: 19,
          fontStyle: "italic",
          fontWeight: 400,
          color: "#f0ebe3",
          opacity: op,
          transition: "opacity 0.08s",
        }}
      >
        "I wish I had told…"
      </p>
      <div
        style={{
          width: 44,
          height: 1,
          background: `linear-gradient(to right,transparent,${accent},transparent)`,
          margin: "1.2rem auto 0",
          opacity: op,
        }}
      />
    </div>
  );
}

