/* ─── NAV BAR ────────────────────────────────────────────── */
function NavBar({
  lang,
  setLang,
  tx,
  scrolled,
  currentBg,
  currentText,
  active,
  onNav,
}) {
  const navText = currentText || B.text;
  const navMuted = currentText ? currentText + "99" : B.muted;
  const navBorder = currentText ? currentText + "44" : B.border;
  const navBtn = (label, target, isActive) => (
    <button
      onClick={() => onNav(target)}
      style={{
        position: "relative",
        background: "none",
        border: "none",
        cursor: "pointer",
        fontSize: 11,
        letterSpacing: "0.1em",
        textTransform: "uppercase",
        color: isActive ? navText : navMuted,
        fontFamily: "'Outfit',sans-serif",
        fontWeight: isActive ? 500 : 400,
        transition: "color 0.25s",
        padding: "3px 0",
      }}
      onMouseEnter={(e) => {
        if (!isActive) e.currentTarget.style.color = navText;
      }}
      onMouseLeave={(e) => {
        if (!isActive) e.currentTarget.style.color = navMuted;
      }}
    >
      {label}
      <span
        style={{
          position: "absolute",
          left: 0,
          bottom: -2,
          height: 1.5,
          width: "100%",
          background: navText,
          transformOrigin: "left center",
          transform: `scaleX(${isActive ? 1 : 0})`,
          transition: "transform 0.35s cubic-bezier(0.16,1,0.3,1)",
        }}
      />
    </button>
  );
  return (
    <nav
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        zIndex: 100,
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "1.1rem 3rem",
        background: currentBg
          ? currentBg
          : scrolled
            ? "rgba(242,240,237,0.94)"
            : "transparent",
        backdropFilter: !currentBg && scrolled ? "blur(14px)" : "none",
        borderBottom: currentBg
          ? `0.5px solid ${navBorder}`
          : scrolled
            ? `0.5px solid ${navBorder}`
            : "0.5px solid transparent",
        transition: "all 0.3s",
      }}
    >
      <button
        onClick={() => onNav("hero")}
        style={{
          background: "none",
          border: "none",
          cursor: "pointer",
          padding: 0,
          fontFamily: "'Cormorant Garamond',serif",
          fontSize: 16,
          fontWeight: 600,
          fontStyle: "italic",
          color: navText,
          opacity: 0.85,
          transition: "opacity 0.2s",
        }}
        onMouseEnter={(e) => (e.currentTarget.style.opacity = 1)}
        onMouseLeave={(e) => (e.currentTarget.style.opacity = 0.85)}
      ></button>
      <div style={{ display: "flex", alignItems: "center", gap: "2rem" }}>
        {navBtn(tx.nav[0], "projects", active === "projects")}
        {navBtn(tx.nav[1], "about", active === "about")}
        {navBtn(tx.nav[2], "contact", active === "contact")}
        <button
          onClick={() => setLang(lang === "it" ? "en" : "it")}
          style={{
            background: "none",
            border: `0.5px solid ${navBorder}`,
            color: navMuted,
            cursor: "pointer",
            fontSize: 10,
            letterSpacing: "0.13em",
            textTransform: "uppercase",
            padding: "4px 13px",
            borderRadius: 20,
            fontFamily: "'Outfit',sans-serif",
            fontWeight: 500,
            transition: "all 0.2s",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.borderColor = navText;
            e.currentTarget.style.color = navText;
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.borderColor = navBorder;
            e.currentTarget.style.color = navMuted;
          }}
        >
          {lang === "it" ? "IT" : "EN"}
        </button>
      </div>
    </nav>
  );
}

