/* ─── APP ────────────────────────────────────────────────── */
export default function App() {
  const [lang, setLang] = useState("it");
  const [projectId, setProjectId] = useState(null); // null = single-page scroll view
  const [scrolled, setScrolled] = useState(false);
  const [active, setActive] = useState("hero");
  const tx = T[lang];

  const heroRef = useRef(null);
  const projectsRef = useRef(null);
  const aboutRef = useRef(null);
  const contactRef = useRef(null);
  const sectionRefs = {
    hero: heroRef,
    projects: projectsRef,
    about: aboutRef,
    contact: contactRef,
  };

  // sticky-nav background after a little scroll
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // scroll-spy: highlight the section currently in view
  useEffect(() => {
    if (projectId) return; // detail page open
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) setActive(e.target.id);
        });
      },
      { rootMargin: "-45% 0px -45% 0px", threshold: 0 },
    );
    Object.values(sectionRefs).forEach(
      (r) => r.current && obs.observe(r.current),
    );
    return () => obs.disconnect();
  }, [projectId, lang]);

  const scrollTo = (target) => {
    const el = sectionRefs[target]?.current;
    if (el)
      el.scrollIntoView({
        behavior: "smooth",
        block: target === "hero" ? "start" : "start",
      });
  };

  const handleNav = (target) => {
    if (projectId) {
      // close detail first, then scroll once the page is back
      setProjectId(null);
      requestAnimationFrame(() =>
        requestAnimationFrame(() => scrollTo(target)),
      );
    } else {
      scrollTo(target);
    }
  };

  const openProject = (id) => {
    setProjectId(id);
    window.scrollTo(0, 0);
  };
  const closeProject = () => {
    setProjectId(null);
    requestAnimationFrame(() => scrollTo("projects"));
  };

  const detail = projectId ? PROJECTS.find((p) => p.id === projectId) : null;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;1,400;1,600&family=Outfit:wght@300;400;500&display=swap');
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
        html{font-size:16px;scroll-behavior:smooth}
        body{background:${B.bg};-webkit-font-smoothing:antialiased}
        @keyframes pageIn{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
        @keyframes floatHint{0%,100%{transform:translate(-50%,0)}50%{transform:translate(-50%,7px)}}
        ::-webkit-scrollbar{width:3px}::-webkit-scrollbar-thumb{background:${B.border};border-radius:2px}
        .proj-grid{display:grid;gap:14px;grid-template-columns:repeat(4,1fr);align-items:stretch;max-width:1280px;margin:0 auto}
        @media(max-width:1024px){.proj-grid{grid-template-columns:repeat(2,1fr)}}
        @media(max-width:560px){.proj-grid{grid-template-columns:1fr}}
        @media(max-width:600px){nav{padding:1rem 1.4rem !important}section#projects{padding-left:1.4rem !important;padding-right:1.4rem !important}}
        .dev-row{display:flex;gap:16px;flex-wrap:wrap;justify-content:center;align-items:flex-start}
        .ba-row{display:flex;align-items:center;justify-content:center;gap:1.1rem;flex-wrap:wrap}
        .ba-group{display:flex;gap:10px;flex-wrap:wrap;justify-content:center}
        .ba-arrow{font-size:26px;line-height:1;flex-shrink:0;transition:transform 0.3s}
        @media(max-width:560px){.ba-row{flex-direction:column}.ba-arrow{transform:rotate(90deg)}}
      `}</style>

      <NavBar
        lang={lang}
        setLang={setLang}
        tx={tx}
        scrolled={scrolled}
        active={projectId ? null : active}
        onNav={handleNav}
        currentBg={detail ? detail.theme.bg : null}
        currentText={detail ? detail.theme.text : null}
      />

      {detail ? (
        <ProjectDetailView
          projectId={projectId}
          lang={lang}
          tx={tx}
          onBack={closeProject}
        />
      ) : (
        <main>
          <HeroSection
            tx={tx}
            sectionRef={heroRef}
            onScrollNext={() => scrollTo("projects")}
          />
          <ProjectsSection
            lang={lang}
            tx={tx}
            sectionRef={projectsRef}
            onOpen={openProject}
          />
          <div style={{ maxWidth: 1280, margin: "0 auto", padding: "0 3rem" }}>
            <hr
              style={{
                border: "none",
                borderTop: `0.5px solid ${B.border}`,
                margin: "1rem 0",
              }}
            />
          </div>
          <AboutSection lang={lang} tx={tx} sectionRef={aboutRef} />
          <ContactSection lang={lang} tx={tx} sectionRef={contactRef} />
        </main>
      )}
    </>
  );
}
